  /router\.(get|post|all|use)\s*\(\s*['"`]\/health/i,
  /server\.(get|post|all|use)\s*\(\s*['"`]\/health/i,
  /fastify\.(get|route)\s*\(\s*\{?\s*url\s*:\s*['"`]\/health/i,
  /return\s+(new\s+)?Response\s*\(\s*['"`]?(OK|ok|healthy|up|running)/i,
  /json\s*\(\s*\{.*status.*:\s*['"`]?(ok|up|healthy)/i,
];

function isTestOrExamplePath(p) {
  return /(\/|^)(test|tests|__tests__|__mocks__|fixtures?|examples?|demo|demos|playground|benchmark|docs|\.github|\.storybook|scripts|dist|build|coverage|storybook|bin|cli|config|vitest|jest|knip|lint-staged|prettier|eslint|\.vscode|node_modules)(\/|$)/i.test(p);
}

function hasProductionStartScript(packageJson) {
  if (!packageJson?.scripts) return false;
  const excluded = /^(docs?|dev|build|watch|storybook|lint|test|tsc|typecheck|clean|bench|benchmark|preview|vite)/i;
  for (const [name, cmd] of Object.entries(packageJson.scripts)) {
    if (name === 'start' || /^start:/i.test(name)) {
      if (cmd && !excluded.test(cmd)) {
        return true;
      }
    }
  }
  return false;
}

function hasHealthDependency(packageJson) {
  if (!packageJson) return null;
  const deps = { ...packageJson.dependencies, ...packageJson.devDependencies, ...packageJson.peerDependencies };
  return Object.keys(deps).find(d => HEALTH_LIBS.has(d)) || null;
}

function hasDeploymentConfig(tree) {
  return tree.some(p => {
    if (isTestOrExamplePath(p)) return false;
    const l = p.toLowerCase();
    return l === 'dockerfile' || l.startsWith('dockerfile.') ||
      /^docker-compose\.(yml|yaml)$/i.test(p) ||
      /^fly\.toml$/i.test(p) ||
      /^render\.yaml$/i.test(p) ||
      /^railway\.toml$/i.test(p) ||
      /^Procfile$/i.test(p) ||
      /^app\.yaml$/i.test(p) ||
      /(^|\/)k8s\//i.test(p) ||
      /(^|\/)kubernetes\//i.test(p) ||
      /(^|\/)helm\//i.test(p) ||
      /^wrangler\.(toml|json)$/i.test(p) ||
      /^netlify\.toml$/i.test(p) ||
      /^vercel\.json$/i.test(p) ||
      /^serverless\.(yml|yaml|json)$/i.test(p);
  });
}

function isFrameworkSource(tree, packageJson) {
  if (hasDeploymentConfig(tree)) return false;
  if (hasProductionStartScript(packageJson)) return false;

  const hasPackages = tree.filter(p => /^packages\/[^/]+\/package\.json$/i.test(p)).length >= 2;
  const hasApps = tree.some(p => /^(apps|services|workers)\/[^/]+\/package\.json$/i.test(p));
  if (hasPackages && !hasApps) {
    const pkgCount = tree.filter(p => /^packages\/[^/]+\/package\.json$/i.test(p)).length;
    if (pkgCount >= 3) return true;
    if (packageJson?.private && (packageJson?.workspaces || tree.some(p => /^pnpm-workspace\.yaml$/i.test(p)))) {
      return true;
    }
  }

  if ((packageJson?.main || packageJson?.module || packageJson?.exports) && !hasProductionStartScript(packageJson)) {
    const hasServerCode = tree.some(p => /^(src\/)?(server|app|main)\.(js|ts|mjs|cjs|jsx|tsx)$/i.test(p) && !isTestOrExamplePath(p));
    const hasApiDir = tree.some(p => /(^|\/)api\/.*\.(js|ts|mjs|cjs|jsx|tsx)$/i.test(p) && !isTestOrExamplePath(p));
    const hasAppRouter = tree.some(p => /(^|\/)app\/.*\/route\.(js|ts|mjs|cjs|jsx|tsx)$/i.test(p) && !isTestOrExamplePath(p));
    if (!hasServerCode && !hasApiDir && !hasAppRouter && !hasApps) return true;
  }

  const exampleCount = tree.filter(p => /^examples?\/[^/]+\//i.test(p)).length;
  if (exampleCount >= 3 && !hasProductionStartScript(packageJson) && !hasApps) return true;
  return false;
}

function isTutorialRepo(tree, packageJson) {
  if (isFrameworkSource(tree, packageJson)) return false;
  if (hasDeploymentConfig(tree)) return false;
  if (hasProductionStartScript(packageJson)) return false;
  if (isBuildTool(packageJson)) return false;
  if (isCliTool(packageJson)) return false;

  const name = (packageJson?.name || '').toLowerCase();
  const desc = (packageJson?.description || '').toLowerCase();
  const text = `${name} ${desc}`;
  const strongTutorialName = /\b(learn|tutorial|course|how[- ]?to|playground|starter[- ]?template|examples?[- ]?app|getting[- ]?started|teach|training|workshop|bootcamp|school|walkthrough|guide[- ]?app)\b/.test(text);
  const tutorialSuffix = /-(learn|tutorial|course|examples?|playground|workshop|walkthrough)$/.test(name);
  if (strongTutorialName || tutorialSuffix) return true;

  const tutorialDirs = ['examples', 'example', 'starters', 'starter', 'learn', 'tutorial', 'tutorials', 'course', 'playground', 'demos', 'demo', 'chapters', 'lessons', 'exercises', 'solutions', 'walkthrough', 'workshop'];
  let dirCount = 0;
  for (const d of tutorialDirs) {
    const hasPkg = tree.some(p => new RegExp(`(^|/)${d}/[^/]+/package\\.json$`, 'i').test(p));
    const hasReadme = tree.some(p => new RegExp(`(^|/)${d}/[^/]+/readme`, 'i').test(p));
    if (hasPkg || hasReadme) dirCount++;
  }
  if (dirCount >= 3) return true;

  const allPkgs = tree.filter(p => /(^|\/)package\.json$/i.test(p) && !/(^|\/)node_modules\//i.test(p));
  const nonRootPkgs = allPkgs.filter(p => p !== 'package.json');
  if (nonRootPkgs.length >= 5) {
    const monorepoDirRe = /\/(packages|apps|services|libs|tools|infra|shared|core|components|ui|config|scripts|e2e|test|tests|docs|storybook|fixtures?)\//i;
    const nonMonorepoPkgCount = nonRootPkgs.filter(p => !monorepoDirRe.test(p)).length;
    if (nonMonorepoPkgCount >= 4) return true;
  }

  return false;
}

function isBuildTool(packageJson) {
  if (!packageJson) return false;
  const text = `${packageJson.name || ''} ${(packageJson.keywords || []).join(' ')}`.toLowerCase();
  return /\b(monorepo|build[- ]?tool|bundler|compiler|task[- ]?runner|orchestrator|cli[- ]?tool|scaffold|generator)\b/.test(text);
}

function isCliTool(packageJson) {
  if (!packageJson) return false;
  return !!packageJson.bin || !!(packageJson.directories?.bin);
}

function isPureLibrary(tree, packageJson) {
  if (!packageJson) return false;
  if (hasProductionStartScript(packageJson)) return false;
  if (hasDeploymentConfig(tree)) return false;
  const hasServerFile = tree.some(p => /^(src\/)?(server|app|main)\.(js|ts|mjs|cjs|jsx|tsx)$/i.test(p) && !isTestOrExamplePath(p));
  const hasApi = tree.some(p => /(^|\/)api\/.*\.(js|ts|mjs|cjs|jsx|tsx)$/i.test(p) && !isTestOrExamplePath(p));
  const hasAppRouter = tree.some(p => /(^|\/)app\/.*\/route\.(js|ts|mjs|cjs|jsx|tsx)$/i.test(p) && !isTestOrExamplePath(p));
  if (hasServerFile || hasApi || hasAppRouter) return false;
  const hasExports = packageJson.exports || packageJson.main || packageJson.module || packageJson.types || packageJson.browser;
  if (!hasExports) return false;
  const hasWorkspaceApps = tree.some(p => /^(apps|services|workers)\/[^/]+\/package\.json$/i.test(p));
  if (hasWorkspaceApps) return false;
  return true;
}

async function isStaticExport(tree, files) {
  const configs = tree.filter(p =>
    /^next\.config\.(js|mjs|ts|jsx|tsx)$/i.test(p) ||
    /^astro\.config\.(mjs|js|ts)$/i.test(p) ||
    /^nuxt\.config\.(ts|js)$/i.test(p) ||
    /^svelte\.config\.(js|ts)$/i.test(p)
  ).slice(0, 3);
  for (const cf of configs) {
    const content = await files.get(cf);
    if (!content) continue;
    if (/output\s*:\s*['"`]export['"`]/.test(content)) return true;
    if (/output\s*:\s*['"`]static['"`]/.test(content)) return true;
    if (/ssr\s*:\s*false/.test(content)) return true;
    if (/target\s*:\s*['"`]static['"`]/.test(content)) return true;
    if (/adapter\s*:\s*static/.test(content)) return true;
  }
  return false;
}

function isPlatformManagedWithoutServer(tree, packageJson) {
  if (!packageJson) return false;
  const deps = { ...packageJson.dependencies, ...packageJson.devDependencies };
  const depList = Object.keys(deps);
  const hasServerDep = depList.some(d => FRAMEWORK_DEPS.has(d));
  const hasCustomServer = tree.some(p => /^(server|app|main)\.(js|ts|mjs|cjs|jsx|tsx)$/i.test(p) && !isTestOrExamplePath(p));
  const hasApiRoutes = tree.some(p => /(^|\/)api\/.*\.(js|ts|mjs|cjs|jsx|tsx)$/i.test(p) && !isTestOrExamplePath(p));
  const hasMiddleware = tree.some(p => /(^|\/)middleware\.(js|ts|mjs|cjs|jsx|tsx)$/i.test(p) && !isTestOrExamplePath(p));
  if (hasCustomServer || hasApiRoutes || hasMiddleware || hasServerDep) return false;

  const platformConfigs = ['vercel.json', 'netlify.toml', 'wrangler.toml', 'app.yaml', 'serverless.yml', 'serverless.yaml', 'serverless.json'];
  const hasPlatformConfig = tree.some(p => platformConfigs.includes(p.toLowerCase()));
  const staticGenerators = ['astro.config', 'gatsby-config', 'eleventy.config', '.eleventy.js', 'vuepress.config', 'docusaurus.config'];
  const hasStaticConfig = tree.some(p => {
    const base = p.toLowerCase().split('/').pop();
    return staticGenerators.some(cfg => base.startsWith(cfg));
  });
  return hasPlatformConfig || hasStaticConfig;
}

function scoreServerFile(path) {
  let score = 0;
  if (/\.(test|spec)\./.test(path)) return -100;
  if (isTestOrExamplePath(path)) return -100;
  if (/^(src\/)?(server|app|main|index)\.(js|ts|mjs|cjs|jsx|tsx)$/i.test(path)) score += 15;
  else if (/(^|\/)((app|pages)\/api|app\/.*\/route\.|api\/|server\/api|src\/api|workers\/|functions\/|controllers\/|handlers\/|routes\/)\//i.test(path)) score += 12;
  else if (/(^|\/)((src\/)?(routes|server|backend|middleware))\//i.test(path)) score += 8;
  else if (/(^|\/)middleware\.(js|ts|mjs|cjs|jsx|tsx)$/i.test(path)) score += 11;
  else if (/(^|\/)((netlify|supabase|edge)[-_]?functions|functions)\//i.test(path)) score += 8;
  else if (/\.(route|router|controller|handler|endpoint|middleware)\./i.test(path)) score += 5;
  else if (/\.(jsx|tsx)$/i.test(path)) score += 1;
  if (path.startsWith('src/')) score += 2;
  if (/[\\/]page\.(jsx|tsx)$/i.test(path) && !/[\\/]api[\\/]/i.test(path)) score -= 4;
  if (/app\/page\.|pages\/(index|_app|_document)\./i.test(path)) score -= 6;
  if (/components?\/|ui\/|widgets?\/|pages\/(?!api)/i.test(path)) score -= 5;
  if (path.split('/').length > 8) score -= 4;
  return score;
}

function isClearlyDeployableServer(tree, packageJson) {
  if (hasDeploymentConfig(tree)) return true;
  const allDeps = { ...packageJson?.dependencies, ...packageJson?.devDependencies, ...packageJson?.peerDependencies };
  const depList = Object.keys(allDeps);
  const hasFrameworkOrServerDep = depList.some(d => FRAMEWORK_DEPS.has(d));
  const hasStart = hasProductionStartScript(packageJson);
  const hasApi = tree.some(p => /(^|\/)api\/[^/]+\.(js|ts|mjs|cjs|jsx|tsx)$/i.test(p) && !isTestOrExamplePath(p));
  const hasServerEntry = tree.some(p => /^(src\/)?(server|app|main)\.(js|ts|mjs|cjs|jsx|tsx)$/i.test(p) && !isTestOrExamplePath(p));
  const hasRoutes = tree.some(p => /(^|\/)routes\/[^/]+\.(js|ts|mjs|cjs|jsx|tsx)$/i.test(p) && !isTestOrExamplePath(p));
  const hasPagesApi = tree.some(p => /(^|\/)pages\/api\/[^/]+\.(js|ts|mjs|cjs|jsx|tsx)$/i.test(p) && !isTestOrExamplePath(p));
  const hasAppRouter = tree.some(p => /(^|\/)app\/[^/]+\/route\.(js|ts|mjs|cjs|jsx|tsx)$/i.test(p) && !isTestOrExamplePath(p));
  const hasMiddleware = tree.some(p => /(^|\/)middleware\.(js|ts|mjs|cjs|jsx|tsx)$/i.test(p) && !isTestOrExamplePath(p));
  const hasWorkers = tree.some(p => /(^|\/)workers?\/[^/]+\.(js|ts|mjs|cjs|jsx|tsx)$/i.test(p) && !isTestOrExamplePath(p));
  const hasFunctions = tree.some(p => /(^|\/)functions\/[^/]+\.(js|ts|mjs|cjs|jsx|tsx)$/i.test(p) && !isTestOrExamplePath(p));
  const hasMetaConfig = tree.some(p => {
    if (isTestOrExamplePath(p)) return false;
    return /(^|\/)next\.config\.(js|mjs|ts|jsx|tsx)$/i.test(p) ||
      /(^|\/)nuxt\.config\.(ts|js)$/i.test(p) ||
      /(^|\/)astro\.config\.(mjs|js|ts)$/i.test(p) ||
      /(^|\/)svelte\.config\.(js|ts)$/i.test(p) ||
      /(^|\/)remix\.config\.(js|ts)$/i.test(p) ||
      /(^|\/)vite\.config\.(js|ts|mjs|mts)$/i.test(p);
  });
  const hasWorkspaceApps = tree.some(p => /^(apps|services|workers)\/[^/]+\/package\.json$/i.test(p));
  const isMonorepo = !!packageJson?.workspaces || tree.some(p => /^pnpm-workspace\.yaml$/i.test(p)) || depList.includes('turbo');

  if (hasStart && (hasFrameworkOrServerDep || hasServerEntry || hasApi || hasRoutes || hasPagesApi || hasAppRouter || hasMiddleware || hasMetaConfig)) return true;
  if (hasFrameworkOrServerDep && (hasApi || hasServerEntry || hasRoutes || hasPagesApi || hasAppRouter || hasMiddleware || hasWorkers || hasFunctions || hasMetaConfig)) return true;
  if (hasMetaConfig && (hasStart || hasApi || hasServerEntry || hasPagesApi || hasAppRouter || hasMiddleware || hasRoutes)) return true;
  if (hasWorkspaceApps && isMonorepo && (hasStart || hasFrameworkOrServerDep || hasMetaConfig)) return true;
  return false;
}

export async function check(context) {
  const { tree, files, packageJson } = context;

  try {
    for (const re of HEALTH_PATH_PATTERNS) {
      const match = tree.find(p => re.test(p) && !isTestOrExamplePath(p));
      if (match) {
        return { checkId, status: 'pass', confidence: 'high', message: `Health endpoint file found: ${match}`, findings: [{ file: match, issue: 'Health route file detected' }] };
      }
    }

    const healthLib = hasHealthDependency(packageJson);
    if (healthLib) {
      return { checkId, status: 'pass', confidence: 'high', message: `Health check library present: ${healthLib}`, findings: [{ file: 'package.json', issue: `Uses ${healthLib}` }] };
    }

    if (packageJson?.scripts) {
      for (const [name] of Object.entries(packageJson.scripts)) {
        if (/^(health|healthcheck|status|ping|ready|alive)/i.test(name)) {
          return { checkId, status: 'pass', confidence: 'high', message: `Health check script found: "${name}"`, findings: [{ file: 'package.json', issue: `Script "${name}" indicates health monitoring` }] };
        }
      }
    }

    const dockerfile = tree.find(p => /(^|\/)dockerfile$/i.test(p) || /(^|\/)dockerfile\./i.test(p));
    if (dockerfile) {
      const content = await files.get(dockerfile);
      if (content && /healthcheck/i.test(content)) {
        return { checkId, status: 'pass', confidence: 'high', message: `HEALTHCHECK instruction in ${dockerfile}`, findings: [{ file: dockerfile, issue: 'Docker HEALTHCHECK found' }] };
      }
    }

    const composeFile = tree.find(p => /^docker-compose\.(yml|yaml)$/i.test(p));
    if (composeFile) {
      const content = await files.get(composeFile);
      if (content && /healthcheck/i.test(content)) {
        return { checkId, status: 'pass', confidence: 'high', message: `Health check in ${composeFile}`, findings: [{ file: composeFile, issue: 'Docker Compose healthcheck found' }] };
      }
    }

    const k8sFiles = tree.filter(p => /(^|\/)k8s\//i.test(p) || /(^|\/)kubernetes\//i.test(p) || /(^|\/)helm\//i.test(p));
    for (const f of k8sFiles.slice(0, 3)) {
      const content = await files.get(f);
      if (content && (/(liveness|readiness|startup)Probe/i.test(content) || /path:\s*\/(health|status|ready|alive|ping)/i.test(content))) {
        return { checkId, status: 'pass', confidence: 'high', message: `K8s health probe in ${f}`, findings: [{ file: f, issue: 'Kubernetes probe detected' }] };
      }
    }

    const platformHealthConfigs = [
      { pattern: /^fly\.toml$/i, re: /http_checks|healthcheck|path\s*=\s*["']\/(health|status|ping)/i },
      { pattern: /^app\.yaml$/i, re: /health_check|readiness_check|liveness_check|\/health/i },
      { pattern: /^render\.yaml$/i, re: /healthCheckPath|\/health/i },
    ];
    for (const { pattern, re } of platformHealthConfigs) {
      const file = tree.find(p => pattern.test(p));
      if (file) {
        const content = await files.get(file);
        if (content && re.test(content)) {
          return { checkId, status: 'pass', confidence: 'high', message: `Health check config in ${file}`, findings: [{ file, issue: 'Platform health check configured' }] };
        }
      }
    }

    const workspacePkgs = tree
      .filter(p => /(^|\/)package\.json$/i.test(p) && !/(^|\/)node_modules\//i.test(p))
      .filter(p => p !== 'package.json')
      .slice(0, 15);

    let workspaceHasDeployableSignals = false;
    for (const p of workspacePkgs) {
      const content = await files.get(p);
      if (!content) continue;
      try {
        const pkg = JSON.parse(content);
        const wsHealthLib = hasHealthDependency(pkg);
        if (wsHealthLib) {
          return { checkId, status: 'pass', confidence: 'high', message: `Health check library in workspace ${p}: ${wsHealthLib}`, findings: [{ file: p, issue: `Uses ${wsHealthLib}` }] };
        }
        if (pkg.scripts) {
          for (const [name] of Object.entries(pkg.scripts)) {
            if (/^(health|healthcheck|status|ping|ready|alive)/i.test(name)) {
              return { checkId, status: 'pass', confidence: 'high', message: `Health check script in workspace ${p}: "${name}"`, findings: [{ file: p, issue: `Script "${name}"` }] };
            }
          }
        }
        const wsDeps = { ...pkg.dependencies, ...pkg.devDependencies };
        if (Object.keys(wsDeps).some(d => FRAMEWORK_DEPS.has(d))) {
          workspaceHasDeployableSignals = true;
        }
        if (hasProductionStartScript(pkg)) {
          workspaceHasDeployableSignals = true;
        }
      } catch (e) { /* ignore parse errors */ }
    }

    const fileCount = tree.filter(p => !p.endsWith('/')).length;
    if (fileCount < 3) {
      return { checkId, status: 'not-applicable', confidence: 'high', message: 'Empty or minimal repository', findings: [] };
    }

    if (isFrameworkSource(tree, packageJson)) {
      return { checkId, status: 'not-applicable', confidence: 'high', message: 'Framework or library source code', findings: [] };
    }

    if (isTutorialRepo(tree, packageJson)) {
      return { checkId, status: 'not-applicable', confidence: 'high', message: 'Tutorial, course, or examples repository', findings: [] };
    }

    if (isBuildTool(packageJson) || isCliTool(packageJson)) {
      return { checkId, status: 'not-applicable', confidence: 'high', message: 'Build tool, CLI, or task runner', findings: [] };
    }

    if (isPureLibrary(tree, packageJson)) {
      return { checkId, status: 'not-applicable', confidence: 'high', message: 'Library package without server or deployment signals', findings: [] };
    }

    if (await isStaticExport(tree, files)) {
      return { checkId, status: 'not-applicable', confidence: 'high', message: 'Static site export detected; health check not required', findings: [] };
    }

    if (isPlatformManagedWithoutServer(tree, packageJson)) {
      return { checkId, status: 'not-applicable', confidence: 'high', message: 'Platform-managed static deployment; health check not required', findings: [] };
    }

    const serverFiles = tree
      .filter(p => /\.(js|ts|mjs|cjs|jsx|tsx)$/i.test(p))
      .map(p => ({ path: p, score: scoreServerFile(p) }))
      .filter(f => f.score > 0)
      .sort((a, b) => b.score - a.score)
      .slice(0, 12)
      .map(f => f.path);

    for (const file of serverFiles) {
      const content = await files.get(file);
      if (!content) continue;
      for (const pattern of HEALTH_CODE_PATTERNS) {
        if (pattern.test(content)) {
          return { checkId, status: 'pass', confidence: 'high', message: `Health endpoint found in ${file}`, findings: [{ file, issue: 'Health route or probe detected' }] };
        }
      }
    }

    const clearlyDeployable = isClearlyDeployableServer(tree, packageJson) || workspaceHasDeployableSignals;

    if (clearlyDeployable) {
      return {
        checkId,
        status: 'fail',
        confidence: 'high',
        message: 'Deployable server detected but no health check endpoint found',
        findings: serverFiles.slice(0, 3).map(f => ({ file: f, issue: 'Server file scanned, no health endpoint found' }))
      };
    }

    const depList = Object.keys({ ...packageJson?.dependencies, ...packageJson?.devDependencies });
    const hasMetaOrServerDep = depList.some(d => FRAMEWORK_DEPS.has(d));
    const hasStart = hasProductionStartScript(packageJson);

    if (serverFiles.length > 0 || (hasMetaOrServerDep && hasStart)) {
      const findings = serverFiles.length > 0
        ? serverFiles.slice(0, 3).map(f => ({ file: f, issue: 'Ambiguous server signals' }))
        : [{ file: 'package.json', issue: 'Has server dependency or start script but no clear server entry files' }];
      return {
        checkId,
        status: 'check-it',
        confidence: 'medium',
        message: 'Server code detected but deployment intent is unclear; verify if a health check is needed',
        findings
      };
    }

    return { checkId, status: 'not-applicable', confidence: 'medium', message: 'No server or deployable signals detected; health check not required', findings: [] };
  } catch (err) {
    console.error(`[health-check] Error:`, err);
    return { checkId, status: 'not-applicable', confidence: 'low', message: `Analysis error: ${err.message}`, findings: [] };
  }
}
